mapper.select:
select * from lab_sub l left join lab_info l2 on l.lab_id = l2.id
where l.is_deleted = 0 and l2.is_deleted = 0

    and l.lab_id = #{labId}


    and l.lab_name like concat('%', #{labName}, '%')


    and l.lab_create_year = #{labCreateYear}


    and l.lab_addr like concat('%', #{labAddr}, '%')


    and l.lab_status = #{labStatus}

order by l.update_time desc
